<canvas id="c"></canvas>
<script>
(() => {
  const canvas = document.getElementById('c');
  const ctx = canvas.getContext('2d');

  let W = 0, H = 0, dpr = 1;
  let state = 'start'; // start | playing | gameover | victory
  let score = 0, lives = 3, level = 1;
  const MAX_LEVEL = 5;

  const paddle = { x: 0, y: 0, w: 100, h: 14, speed: 9 };
  const ball = { x: 0, y: 0, r: 8, dx: 0, dy: 0, speed: 5.2, stuck: true };
  let bricks = [];
  let particles = [];

  const keys = {};
  let mouseX = 0;
  let touchX = null;
  let control = 'mouse'; // mouse | keyboard | touch

  const NEON = ['#ff00ff', '#00ffff', '#39ff14', '#ffff00', '#ff6600', '#ff1493', '#bf00ff'];

  // ---------- Audio (Web Audio API synthesized) ----------
  let actx = null;

  function ensureAudio() {
    if (!actx) {
      actx = new (window.AudioContext || window.webkitAudioContext)();
    }
    if (actx.state === 'suspended') actx.resume();
  }

  function tone(freq, type, dur, vol = 0.09, slide = null) {
    if (!actx) return;
    const o = actx.createOscillator();
    const g = actx.createGain();
    o.type = type;
    o.frequency.setValueAtTime(freq, actx.currentTime);
    if (slide) o.frequency.exponentialRampToValueAtTime(Math.max(20, slide), actx.currentTime + dur);
    g.gain.setValueAtTime(vol, actx.currentTime);
    g.gain.exponentialRampToValueAtTime(0.001, actx.currentTime + dur);
    o.connect(g);
    g.connect(actx.destination);
    o.start();
    o.stop(actx.currentTime + dur + 0.02);
  }

  function noise(dur, vol = 0.07) {
    if (!actx) return;
    const len = actx.sampleRate * dur;
    const buf = actx.createBuffer(1, len, actx.sampleRate);
    const data = buf.getChannelData(0);
    for (let i = 0; i < len; i++) data[i] = Math.random() * 2 - 1;
    const src = actx.createBufferSource();
    src.buffer = buf;
    const g = actx.createGain();
    const f = actx.createBiquadFilter();
    f.type = 'bandpass';
    f.frequency.value = 900;
    f.Q.value = 0.7;
    g.gain.setValueAtTime(vol, actx.currentTime);
    g.gain.exponentialRampToValueAtTime(0.001, actx.currentTime + dur);
    src.connect(f);
    f.connect(g);
    g.connect(actx.destination);
    src.start();
  }

  function sfx(name) {
    ensureAudio();
    switch (name) {
      case 'paddle': tone(180, 'square', 0.07, 0.07); break;
      case 'wall':   tone(240, 'sine', 0.05, 0.04); break;
      case 'brick':  tone(380 + Math.random() * 180, 'square', 0.09, 0.08); break;
      case 'break':  noise(0.18, 0.09); tone(320, 'sawtooth', 0.16, 0.07, 80); break;
      case 'life':   tone(220, 'sawtooth', 0.35, 0.1, 55); break;
      case 'launch': tone(340, 'triangle', 0.1, 0.07); break;
      case 'level':
        tone(440, 'square', 0.09, 0.08);
        setTimeout(() => tone(554, 'square', 0.09, 0.08), 90);
        setTimeout(() => tone(659, 'square', 0.14, 0.09), 180);
